```class Solution {
public:
    int distanceTraveled(int mainTank, int additionalTank) {
        int mainFuelLeft = mainTank;
        int additionalFuelLeft = additionalTank;
        int distance = 0;

        while (mainFuelLeft >= 5 || additionalFuelLeft >= 1) {
            distance += 10; // Travel 10 km per liter
            mainFuelLeft -= 5;
            additionalFuelLeft -= 1;
        }

        return distance;
    }
};```

